@namespace Lumeo

@if (Label is not null && !InsideFormField)
{
    <label class="text-sm font-medium leading-none">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

@if (Variant == DatePickerVariant.Wheel)
{
    @* iOS-style 3-column wheel picker. v1 limitations:
       - Only honours single-date Mode (Range/Month/Year fall back to a day/month/year wheel).
       - No Presets sidebar.
       - ShowTimePicker is supported via a stacked TimeWheelPicker below the date wheel.
    *@
    @if (Inline)
    {
        <div>
            <DateWheelPicker Value="@Value" ValueChanged="HandleDateSelected" Min="@MinDate" Max="@MaxDate" Culture="@Culture" />
            @if (ShowTimePicker)
            {
                <div class="border-t border-border/40 p-3">
                    <TimePicker Value="@Time" ValueChanged="HandleTimeChanged" Culture="@Culture" Variant="TimePicker.TimePickerVariant.Wheel" />
                </div>
            }
        </div>
    }
    else
    {
        <Popover @bind-Open="_isOpen">
            <PopoverTrigger>
                <button type="button"
                        name="@Name"
                        aria-required="@Required.ToString().ToLower()"
                        aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                        class="@CssClass"
                        disabled="@Disabled"
                        @attributes="AdditionalAttributes">
                    <Blazicon Svg="Lucide.Calendar" class="me-2 h-4 w-4 shrink-0" />
                    @if (TriggerContent != null)
                    {
                        @TriggerContent
                    }
                    else if (Value.HasValue)
                    {
                        <span>@Value.Value.ToString(EffectiveFormat, EffectiveCulture)</span>
                    }
                    else
                    {
                        <span class="text-muted-foreground">@EffectivePlaceholder</span>
                    }
                    @if (Clearable && HasValue)
                    {
                        <button type="button" class="ms-auto ps-1 hover:text-foreground" aria-label="@L["Common.Clear"]" @onclick="HandleClear" @onclick:stopPropagation="true">
                            <Blazicon Svg="Lucide.X" class="h-3.5 w-3.5" />
                        </button>
                    }
                </button>
            </PopoverTrigger>
            <PopoverContent Align="PopoverContent.PopoverAlign.Start" Class="w-[260px] p-3">
                <DateWheelPicker Value="@Value" ValueChanged="HandleDateSelected" Min="@MinDate" Max="@MaxDate" Culture="@Culture" />
                @if (ShowTimePicker)
                {
                    <div class="border-t border-border/40 mt-3 pt-3">
                        <TimePicker Value="@Time" ValueChanged="HandleTimeChanged" Culture="@Culture" Variant="TimePicker.TimePickerVariant.Wheel" />
                    </div>
                }
            </PopoverContent>
        </Popover>
    }
}
else if (Inline)
{
        @if (Mode == DatePickerMode.Month)
        {
            <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" InitialView="@Calendar.CalendarView.Months" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
        }
        else if (Mode == DatePickerMode.Year)
        {
            <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" InitialView="@Calendar.CalendarView.Years" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
        }
        else if (Mode == DatePickerMode.Range)
        {
            @if (Presets != null && Presets.Count > 0)
            {
                <div class="flex">
                    <div class="flex flex-col gap-1 border-e border-border/40 p-2 min-w-[120px]">
                        @foreach (var preset in Presets)
                        {
                            var p = preset;
                            <button type="button" class="text-sm px-3 py-1.5 rounded-md text-left hover:bg-accent hover:text-accent-foreground transition-colors" @onclick="() => HandlePresetSelected(p)">
                                @p.Label
                            </button>
                        }
                    </div>
                    <Calendar IsRange="true" RangeStart="@RangeStart" RangeStartChanged="HandleRangeStartChanged"
                              RangeEnd="@RangeEnd" RangeEndChanged="HandleRangeEndChanged"
                              MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
                </div>
            }
            else
            {
                <Calendar IsRange="true" RangeStart="@RangeStart" RangeStartChanged="HandleRangeStartChanged"
                          RangeEnd="@RangeEnd" RangeEndChanged="HandleRangeEndChanged"
                          MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
            }
        }
        else
        {
            <div>
                @if (Presets != null && Presets.Count > 0)
                {
                    <div class="flex">
                        <div class="flex flex-col gap-1 border-e border-border/40 p-2 min-w-[120px]">
                            @foreach (var preset in Presets)
                            {
                                var p = preset;
                                <button type="button" class="text-sm px-3 py-1.5 rounded-md text-left hover:bg-accent hover:text-accent-foreground transition-colors" @onclick="() => HandlePresetSelected(p)">
                                    @p.Label
                                </button>
                            }
                        </div>
                        <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
                    </div>
                }
                else
                {
                    <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
                }

                @if (ShowTimePicker)
                {
                    <div class="border-t border-border/40 p-3">
                        <TimePicker Value="@Time" ValueChanged="HandleTimeChanged" Culture="@Culture" />
                    </div>
                }
            </div>
        }
}
else
{
    <Popover @bind-Open="_isOpen">
        <PopoverTrigger>
            <button type="button"
                    name="@Name"
                    aria-required="@Required.ToString().ToLower()"
                    aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                    class="@CssClass"
                    disabled="@Disabled"
                    @attributes="AdditionalAttributes">
                <Blazicon Svg="Lucide.Calendar" class="me-2 h-4 w-4 shrink-0" />
                @if (TriggerContent != null)
                {
                    @TriggerContent
                }
                else if (Mode == DatePickerMode.Range)
                {
                    @if (RangeStart.HasValue && RangeEnd.HasValue)
                    {
                        <span>@RangeStart.Value.ToString(EffectiveFormat, EffectiveCulture) - @RangeEnd.Value.ToString(EffectiveFormat, EffectiveCulture)</span>
                    }
                    else if (RangeStart.HasValue)
                    {
                        <span>@RangeStart.Value.ToString(EffectiveFormat, EffectiveCulture) - ...</span>
                    }
                    else
                    {
                        <span class="text-muted-foreground">@EffectivePlaceholder</span>
                    }
                }
                else if (Mode == DatePickerMode.Month)
                {
                    @if (Value.HasValue)
                    {
                        <span>@Value.Value.ToString("MMMM yyyy", EffectiveCulture)</span>
                    }
                    else
                    {
                        <span class="text-muted-foreground">@EffectivePlaceholder</span>
                    }
                }
                else if (Mode == DatePickerMode.Year)
                {
                    @if (Value.HasValue)
                    {
                        <span>@Value.Value.Year</span>
                    }
                    else
                    {
                        <span class="text-muted-foreground">@EffectivePlaceholder</span>
                    }
                }
                else
                {
                    @if (Value.HasValue)
                    {
                        <span>@Value.Value.ToString(EffectiveFormat, EffectiveCulture)</span>
                    }
                    else
                    {
                        <span class="text-muted-foreground">@EffectivePlaceholder</span>
                    }
                }

                @if (Clearable && HasValue)
                {
                    <button type="button" class="ms-auto ps-1 hover:text-foreground" aria-label="@L["Common.Clear"]" @onclick="HandleClear" @onclick:stopPropagation="true">
                        <Blazicon Svg="Lucide.X" class="h-3.5 w-3.5" />
                    </button>
                }
            </button>
        </PopoverTrigger>
        <PopoverContent Align="PopoverContent.PopoverAlign.Start" Class="w-auto p-0">
            @if (Mode == DatePickerMode.Month)
            {
                <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" InitialView="@Calendar.CalendarView.Months" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
            }
            else if (Mode == DatePickerMode.Year)
            {
                <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" InitialView="@Calendar.CalendarView.Years" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
            }
            else if (Mode == DatePickerMode.Range)
            {
                @if (Presets != null && Presets.Count > 0)
                {
                    <div class="flex">
                        <div class="flex flex-col gap-1 border-e border-border/40 p-2 min-w-[120px]">
                            @foreach (var preset in Presets)
                            {
                                var p = preset;
                                <button type="button" class="text-sm px-3 py-1.5 rounded-md text-left hover:bg-accent hover:text-accent-foreground transition-colors" @onclick="() => HandlePresetSelected(p)">
                                    @p.Label
                                </button>
                            }
                        </div>
                        <Calendar IsRange="true" RangeStart="@RangeStart" RangeStartChanged="HandleRangeStartChanged"
                                  RangeEnd="@RangeEnd" RangeEndChanged="HandleRangeEndChanged"
                                  MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
                    </div>
                }
                else
                {
                    <Calendar IsRange="true" RangeStart="@RangeStart" RangeStartChanged="HandleRangeStartChanged"
                              RangeEnd="@RangeEnd" RangeEndChanged="HandleRangeEndChanged"
                              MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
                }
            }
            else
            {
                <div>
                    @if (Presets != null && Presets.Count > 0)
                    {
                        <div class="flex">
                            <div class="flex flex-col gap-1 border-e border-border/40 p-2 min-w-[120px]">
                                @foreach (var preset in Presets)
                                {
                                    var p = preset;
                                    <button type="button" class="text-sm px-3 py-1.5 rounded-md text-left hover:bg-accent hover:text-accent-foreground transition-colors" @onclick="() => HandlePresetSelected(p)">
                                        @p.Label
                                    </button>
                                }
                            </div>
                            <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
                        </div>
                    }
                    else
                    {
                        <Calendar Value="@Value" ValueChanged="HandleDateSelected" MinDate="@MinDate" MaxDate="@MaxDate" IsDateDisabled="@IsDateDisabled" DateClass="@DateClass" DateTooltip="@DateTooltip" DateBadge="@DateBadge" NumberOfMonths="@EffectiveNumberOfMonths" FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers" />
                    }

                    @if (ShowTimePicker)
                    {
                        <div class="border-t border-border/40 p-3">
                            <TimePicker Value="@Time" ValueChanged="HandleTimeChanged" Culture="@Culture" />
                        </div>
                    }
                </div>
            }
        </PopoverContent>
    </Popover>
}

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground">@HelperText</p>
    }
}

@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    public enum DatePickerMode { Single, Range, Month, Year }

    /// <summary>
    /// Visual style of the picker.
    /// <see cref="DatePickerVariant.Calendar"/> renders the existing month-grid Calendar (default).
    /// <see cref="DatePickerVariant.Wheel"/> renders three iOS-style snap-scrolling
    /// columns (day / month / year) — designed for mobile / touch UIs.
    /// </summary>
    public enum DatePickerVariant { Calendar, Wheel }

    /// <summary>Picker visual style. Defaults to <see cref="DatePickerVariant.Calendar"/>.</summary>
    [Parameter] public DatePickerVariant Variant { get; set; } = DatePickerVariant.Calendar;

    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    [Parameter] public DateOnly? Value { get; set; }
    [Parameter] public EventCallback<DateOnly?> ValueChanged { get; set; }

    /// <summary>
    /// Optional DateTime? binding. When set, takes precedence over <see cref="Value"/>.
    /// Changes fire both <see cref="ValueChanged"/> (DateOnly?) and <see cref="DateTimeValueChanged"/> (DateTime? at midnight).
    /// </summary>
    [Parameter] public DateTime? DateTimeValue { get; set; }
    [Parameter] public EventCallback<DateTime?> DateTimeValueChanged { get; set; }

    [Parameter] public string? Placeholder { get; set; }

    private string EffectivePlaceholder => Placeholder ?? (Mode == DatePickerMode.Range ? L["DateRange.Placeholder"] : L["DatePicker.Placeholder"]);
    /// <summary>
    /// Date format string. When null (default), the display falls back to the current
    /// culture's <c>ShortDatePattern</c> — so a <c>de-DE</c> user sees <c>15.03.2026</c>
    /// and an <c>en-US</c> user sees <c>3/15/2026</c> automatically.
    /// </summary>
    [Parameter] public string? Format { get; set; }

    /// <summary>
    /// Overrides <see cref="System.Globalization.CultureInfo.CurrentCulture"/> for
    /// parsing and formatting within this picker. Leave null to honour ASP.NET
    /// request localization.
    /// </summary>
    [Parameter] public System.Globalization.CultureInfo? Culture { get; set; }

    private System.Globalization.CultureInfo EffectiveCulture => Culture ?? System.Globalization.CultureInfo.CurrentCulture;
    private string EffectiveFormat => Format ?? EffectiveCulture.DateTimeFormat.ShortDatePattern;
    [Parameter] public DateOnly? MinDate { get; set; }
    [Parameter] public DateOnly? MaxDate { get; set; }
    /// <summary>Custom predicate to disable specific dates (e.g. booked rooms,
    /// unavailable slots). Returns <c>true</c> for dates that should not be
    /// selectable.</summary>
    [Parameter] public Func<DateTime, bool>? IsDateDisabled { get; set; }
    /// <summary>Custom CSS classes per day cell (e.g. status backgrounds for
    /// booking calendars).</summary>
    [Parameter] public Func<DateTime, string>? DateClass { get; set; }
    /// <summary>Per-date tooltip text rendered as the day cell's <c>title</c>
    /// attribute (native browser tooltip).</summary>
    [Parameter] public Func<DateTime, string?>? DateTooltip { get; set; }
    /// <summary>Per-date indicator slot (status dots, count badges, icons)
    /// rendered absolutely positioned in the bottom-right of the day cell.</summary>
    [Parameter] public Func<DateTime, RenderFragment?>? DateBadge { get; set; }
    [Parameter] public List<DatePickerPreset>? Presets { get; set; }
    [Parameter] public DatePickerMode Mode { get; set; } = DatePickerMode.Single;
    [Parameter] public DateOnly? RangeStart { get; set; }
    [Parameter] public EventCallback<DateOnly?> RangeStartChanged { get; set; }
    [Parameter] public DateOnly? RangeEnd { get; set; }
    [Parameter] public EventCallback<DateOnly?> RangeEndChanged { get; set; }
    [Parameter] public bool ShowTimePicker { get; set; }
    [Parameter] public TimeSpan? Time { get; set; }
    [Parameter] public EventCallback<TimeSpan?> TimeChanged { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool Clearable { get; set; }
    [Parameter] public RenderFragment? TriggerContent { get; set; }
    [Parameter] public int NumberOfMonths { get; set; } = 1;

    /// <summary>
    /// Optional controlled-mode override for the popover open state. When non-null,
    /// the consumer holds the source of truth — the picker no longer mutates its
    /// internal state and instead raises <see cref="OpenChanged"/>. Use this when
    /// the picker lives inside a parent that re-renders heavily (e.g. an
    /// <c>EditForm</c> with active <c>DataAnnotationsValidator</c>) and the
    /// popover would otherwise close mid-click during a parameter cascade.
    /// When null (default), the picker falls back to its internal open state and
    /// behaves exactly as before.
    /// </summary>
    /// <summary>When true, renders the calendar inline (always visible) without a popover wrapper.</summary>
    [Parameter] public bool Inline { get; set; }

    /// <summary>Leftmost column day of week. Null means culture default.</summary>
    [Parameter] public DayOfWeek? FirstDayOfWeek { get; set; }

    /// <summary>When true, renders an ISO week-number column.</summary>
    [Parameter] public bool ShowWeekNumbers { get; set; }

    [Parameter] public bool? Open { get; set; }

    /// <summary>
    /// Fires whenever the popover would open or close. Pair with
    /// <see cref="Open"/> via <c>@bind-Open</c> for the controlled-mode pattern
    /// described above.
    /// </summary>
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Controlled-mode bridge: when Open is non-null, the parent owns the state and
    // we never write to _internalOpen — every "set" just raises OpenChanged so the
    // parent can decide. When Open is null, _internalOpen is the source of truth.
    private bool _internalOpen;
    private bool _isOpen
    {
        get => Open ?? _internalOpen;
        set => SetIsOpen(value);
    }

    private void SetIsOpen(bool value)
    {
        if (Open is null)
        {
            _internalOpen = value;
        }
        if (OpenChanged.HasDelegate)
        {
            _ = OpenChanged.InvokeAsync(value);
        }
    }

    private DateTime? _prevDateTimeValue;

    protected override void OnParametersSet()
    {
        // DateTimeValue wins when it changes — sync Value from it.
        if (DateTimeValue != _prevDateTimeValue)
        {
            _prevDateTimeValue = DateTimeValue;
            Value = DateTimeValue.HasValue ? DateOnly.FromDateTime(DateTimeValue.Value) : null;
        }
    }

    private int EffectiveNumberOfMonths => NumberOfMonths > 1 ? NumberOfMonths : (Mode == DatePickerMode.Range ? 2 : 1);

    private bool HasValue => Mode == DatePickerMode.Range ? RangeStart.HasValue : Value.HasValue;

    private string CssClass => $"flex h-9 w-full items-center rounded-md border {(EffectiveInvalid ? "border-destructive ring-1 ring-destructive/20" : "border-input")} bg-transparent px-3 py-2 text-sm shadow-sm hover:bg-accent hover:text-accent-foreground disabled:cursor-not-allowed disabled:opacity-50 {Class}".Trim();

    private async Task HandleDateSelected(DateOnly? date)
    {
        if (Mode == DatePickerMode.Month && date.HasValue)
        {
            Value = new DateOnly(date.Value.Year, date.Value.Month, 1);
            await ValueChanged.InvokeAsync(Value);
            await RaiseDateTimeValueChanged(Value);
            _isOpen = false;
        }
        else if (Mode == DatePickerMode.Year && date.HasValue)
        {
            Value = new DateOnly(date.Value.Year, 1, 1);
            await ValueChanged.InvokeAsync(Value);
            await RaiseDateTimeValueChanged(Value);
            _isOpen = false;
        }
        else
        {
            Value = date;
            await ValueChanged.InvokeAsync(date);
            await RaiseDateTimeValueChanged(date);
            if (!ShowTimePicker)
            {
                _isOpen = false;
            }
        }
    }

    private async Task HandleRangeStartChanged(DateOnly? date)
    {
        RangeStart = date;
        await RangeStartChanged.InvokeAsync(date);
    }

    private async Task HandleRangeEndChanged(DateOnly? date)
    {
        RangeEnd = date;
        await RangeEndChanged.InvokeAsync(date);
        if (date.HasValue)
        {
            _isOpen = false;
        }
    }

    private async Task HandleTimeChanged(TimeSpan? time)
    {
        Time = time;
        await TimeChanged.InvokeAsync(time);
    }

    private async Task HandlePresetSelected(DatePickerPreset preset)
    {
        Value = preset.Date;
        await ValueChanged.InvokeAsync(preset.Date);
        await RaiseDateTimeValueChanged(preset.Date);
        _isOpen = false;
    }

    private async Task HandleClear()
    {
        if (Mode == DatePickerMode.Range)
        {
            RangeStart = null;
            RangeEnd = null;
            await RangeStartChanged.InvokeAsync(null);
            await RangeEndChanged.InvokeAsync(null);
        }
        else
        {
            Value = null;
            await ValueChanged.InvokeAsync(null);
            await RaiseDateTimeValueChanged(null);
        }
        if (ShowTimePicker)
        {
            Time = null;
            await TimeChanged.InvokeAsync(null);
        }
    }

    private async Task RaiseDateTimeValueChanged(DateOnly? date)
    {
        if (DateTimeValueChanged.HasDelegate)
        {
            var dt = date.HasValue ? (DateTime?)date.Value.ToDateTime(TimeOnly.MinValue) : null;
            _prevDateTimeValue = dt;
            await DateTimeValueChanged.InvokeAsync(dt);
        }
    }

    public record DatePickerPreset(string Label, DateOnly Date);
}

@namespace Lumeo

<DatePicker Mode="DatePicker.DatePickerMode.Range" NumberOfMonths="2"
            RangeStart="@StartDate" RangeStartChanged="@StartDateChanged"
            RangeEnd="@EndDate" RangeEndChanged="@EndDateChanged"
            MinDate="@MinDate" MaxDate="@MaxDate"
            IsDateDisabled="@IsDateDisabled" DateClass="@DateClass"
            DateTooltip="@DateTooltip" DateBadge="@DateBadge"
            Placeholder="@EffectivePlaceholder" Format="@Format"
            Presets="@_datePickerPresets"
            Disabled="@Disabled"
            Clearable="@Clearable"
            Class="@Class"
            FirstDayOfWeek="@FirstDayOfWeek" ShowWeekNumbers="@ShowWeekNumbers"
            @attributes="AdditionalAttributes" />

@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [Parameter] public DateOnly? StartDate { get; set; }
    [Parameter] public EventCallback<DateOnly?> StartDateChanged { get; set; }
    [Parameter] public DateOnly? EndDate { get; set; }
    [Parameter] public EventCallback<DateOnly?> EndDateChanged { get; set; }
    [Parameter] public DateOnly? MinDate { get; set; }
    [Parameter] public DateOnly? MaxDate { get; set; }
    /// <summary>Custom predicate to disable specific dates (e.g. booked
    /// rooms). Returns <c>true</c> for dates that should not be selectable.</summary>
    [Parameter] public Func<DateTime, bool>? IsDateDisabled { get; set; }
    /// <summary>Custom CSS classes per day cell — forwarded to inner Calendar.</summary>
    [Parameter] public Func<DateTime, string>? DateClass { get; set; }
    /// <summary>Per-date tooltip text rendered as the day cell's <c>title</c>.</summary>
    [Parameter] public Func<DateTime, string?>? DateTooltip { get; set; }
    /// <summary>Per-date indicator slot rendered absolutely positioned in the
    /// bottom-right of the day cell.</summary>
    [Parameter] public Func<DateTime, RenderFragment?>? DateBadge { get; set; }
    [Parameter] public string? Placeholder { get; set; }

    private string EffectivePlaceholder => Placeholder ?? L["DateRange.Placeholder"];
    /// <summary>
    /// Date format. When null (default) the inner <see cref="DatePicker"/> falls back
    /// to the effective culture's <c>ShortDatePattern</c> — so a <c>de-DE</c> user sees
    /// <c>15.03.2026</c> and an <c>en-US</c> user sees <c>3/15/2026</c> automatically.
    /// </summary>
    [Parameter] public string? Format { get; set; }
    [Parameter] public List<DateRangePreset>? Presets { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool Clearable { get; set; } = true;
    [Parameter] public DayOfWeek? FirstDayOfWeek { get; set; }
    [Parameter] public bool ShowWeekNumbers { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private List<DatePicker.DatePickerPreset>? _datePickerPresets =>
        Presets?.Select(p => new DatePicker.DatePickerPreset(p.Label, p.Start)).ToList();

    public class DateRangePreset
    {
        public string Label { get; set; } = "";
        public DateOnly Start { get; set; }
        public DateOnly End { get; set; }
    }
}

@namespace Lumeo
@using System.Globalization
@implements IDisposable

<div class="@RootCssClass" @attributes="AdditionalAttributes" style="@RootStyle">
    @* Center selection indicator (overlays all columns) *@
    <div class="absolute left-0 right-0 top-1/2 -translate-y-1/2 h-10 border-y border-primary/30 pointer-events-none"></div>

    @* Day column *@
    <div class="flex-1 overflow-y-scroll snap-y snap-mandatory scrollbar-none h-full"
         @onscroll="OnDayScroll"
         @ref="_dayCol">
        <div class="h-[60px]"></div>
        @for (var d = 1; d <= _daysInMonth; d++)
        {
            var day = d;
            <div class="h-10 flex items-center justify-center snap-center text-base select-none @(day == _day ? "text-primary font-semibold" : "text-muted-foreground")">
                @day
            </div>
        }
        <div class="h-[60px]"></div>
    </div>

    @* Month column *@
    <div class="flex-1 overflow-y-scroll snap-y snap-mandatory scrollbar-none h-full"
         @onscroll="OnMonthScroll"
         @ref="_monthCol">
        <div class="h-[60px]"></div>
        @for (var m = 1; m <= 12; m++)
        {
            var month = m;
            var name = MonthLabel(month);
            <div class="h-10 flex items-center justify-center snap-center text-base select-none px-1 truncate @(month == _month ? "text-primary font-semibold" : "text-muted-foreground")">
                @name
            </div>
        }
        <div class="h-[60px]"></div>
    </div>

    @* Year column *@
    <div class="flex-1 overflow-y-scroll snap-y snap-mandatory scrollbar-none h-full"
         @onscroll="OnYearScroll"
         @ref="_yearCol">
        <div class="h-[60px]"></div>
        @foreach (var yr in _years)
        {
            var year = yr;
            <div class="h-10 flex items-center justify-center snap-center text-base select-none @(year == _year ? "text-primary font-semibold" : "text-muted-foreground")">
                @year
            </div>
        }
        <div class="h-[60px]"></div>
    </div>
</div>

@inject Lumeo.Services.IComponentInteropService Interop

@code {
    // --- Public API ----------------------------------------------------------
    [Parameter] public DateOnly? Value { get; set; }
    [Parameter] public EventCallback<DateOnly?> ValueChanged { get; set; }
    [Parameter] public DateOnly? Min { get; set; }
    [Parameter] public DateOnly? Max { get; set; }
    [Parameter] public CultureInfo? Culture { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // --- Layout constants (must match markup) --------------------------------
    private const int ItemHeight = 40;   // h-10
    private const int Height = 160;      // overall column height

    // --- Element refs --------------------------------------------------------
    private ElementReference _dayCol;
    private ElementReference _monthCol;
    private ElementReference _yearCol;

    // --- Selection state -----------------------------------------------------
    private int _day = 1;
    private int _month = 1;
    private int _year = DateTime.Today.Year;
    private int _daysInMonth = 31;
    private List<int> _years = new();

    // Debounce timer state — one per column so a scroll on one column doesn't
    // cancel pending settle on another.
    private System.Threading.Timer? _dayTimer;
    private System.Threading.Timer? _monthTimer;
    private System.Threading.Timer? _yearTimer;
    private int _pendingDay;
    private int _pendingMonth;
    private int _pendingYear;
    private bool _initialised;

    private CultureInfo EffectiveCulture => Culture ?? CultureInfo.CurrentCulture;

    private string RootCssClass => $"flex gap-2 relative {Class}".Trim();
    private string RootStyle => $"height: {Height}px;";

    protected override void OnParametersSet()
    {
        var seed = Value ?? DateOnly.FromDateTime(DateTime.Today);
        _day = seed.Day;
        _month = seed.Month;
        _year = seed.Year;

        var minYear = Min?.Year ?? DateTime.Today.Year - 50;
        var maxYear = Max?.Year ?? DateTime.Today.Year + 50;
        if (maxYear < minYear) maxYear = minYear;

        _years = Enumerable.Range(minYear, maxYear - minYear + 1).ToList();
        _daysInMonth = DateTime.DaysInMonth(_year, _month);
        if (_day > _daysInMonth) _day = _daysInMonth;
    }

    private string MonthLabel(int month)
    {
        var names = EffectiveCulture.DateTimeFormat.AbbreviatedMonthNames;
        if (month - 1 < names.Length && !string.IsNullOrWhiteSpace(names[month - 1]))
        {
            return names[month - 1];
        }
        return month.ToString("D2");
    }

    // --- Scroll handlers -----------------------------------------------------
    private async Task OnDayScroll()
    {
        if (!_initialised) return; // ignore the programmatic OnAfterRender scroll
        var idx = await GetIndexAsync(_dayCol);
        if (idx < 0) return;
        var day = Math.Clamp(idx + 1, 1, _daysInMonth);
        _pendingDay = day;
        ResetTimer(ref _dayTimer, CommitDay);
    }

    private async Task OnMonthScroll()
    {
        if (!_initialised) return;
        var idx = await GetIndexAsync(_monthCol);
        if (idx < 0) return;
        var month = Math.Clamp(idx + 1, 1, 12);
        _pendingMonth = month;
        ResetTimer(ref _monthTimer, CommitMonth);
    }

    private async Task OnYearScroll()
    {
        if (!_initialised) return;
        var idx = await GetIndexAsync(_yearCol);
        if (idx < 0 || idx >= _years.Count) return;
        _pendingYear = _years[idx];
        ResetTimer(ref _yearTimer, CommitYear);
    }

    private async Task<int> GetIndexAsync(ElementReference el)
    {
        var scrollTop = await Interop.WheelScrollTop(el);
        // Each item is `ItemHeight` tall; the first item sits 60px below the top
        // (top spacer). When item 0 is centered in the 160px viewport,
        // scrollTop = (60 + ItemHeight/2) - 160/2 = 60 + 20 - 80 = 0. So
        // index = round(scrollTop / ItemHeight).
        return (int)Math.Round(scrollTop / ItemHeight);
    }

    private void ResetTimer(ref System.Threading.Timer? timer, Action commit)
    {
        timer?.Dispose();
        timer = new System.Threading.Timer(_ => InvokeAsync(commit), null, 100, System.Threading.Timeout.Infinite);
    }

    private async void CommitDay()
    {
        if (_pendingDay == _day) return;
        _day = _pendingDay;
        await RaiseChange();
        StateHasChanged();
    }

    private async void CommitMonth()
    {
        if (_pendingMonth == _month) return;
        _month = _pendingMonth;
        _daysInMonth = DateTime.DaysInMonth(_year, _month);
        if (_day > _daysInMonth) _day = _daysInMonth;
        await RaiseChange();
        StateHasChanged();
    }

    private async void CommitYear()
    {
        if (_pendingYear == _year) return;
        _year = _pendingYear;
        _daysInMonth = DateTime.DaysInMonth(_year, _month);
        if (_day > _daysInMonth) _day = _daysInMonth;
        await RaiseChange();
        StateHasChanged();
    }

    private async Task RaiseChange()
    {
        try
        {
            var d = new DateOnly(_year, _month, _day);
            if (Min.HasValue && d < Min.Value) d = Min.Value;
            if (Max.HasValue && d > Max.Value) d = Max.Value;
            _year = d.Year; _month = d.Month; _day = d.Day;
            await ValueChanged.InvokeAsync(d);
        }
        catch (ArgumentOutOfRangeException)
        {
            // Defensive — DateOnly ctor guards against invalid combos. We already
            // re-clamp days on month/year change, so this branch is unreachable
            // under normal flow.
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await Interop.WheelScrollTo(_dayCol, (_day - 1) * ItemHeight);
            await Interop.WheelScrollTo(_monthCol, (_month - 1) * ItemHeight);
            var yearIdx = _years.IndexOf(_year);
            if (yearIdx >= 0)
            {
                await Interop.WheelScrollTo(_yearCol, yearIdx * ItemHeight);
            }
            // Defer enabling scroll handlers until after the programmatic
            // scrollTo writes have settled — otherwise the first @onscroll
            // would interpret the seed scroll as a user gesture.
            _ = Task.Delay(150).ContinueWith(_ => InvokeAsync(() => { _initialised = true; }));
        }
    }

    public void Dispose()
    {
        _dayTimer?.Dispose();
        _monthTimer?.Dispose();
        _yearTimer?.Dispose();
    }
}
